module shift_register(CLK, RST, SHIFT_EN, Q);
input CLK, RST, SHIFT_EN;
output [3:0] Q;
reg [3:0] Q;

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge CLK or posedge RST or posedge dbg_halt) begin
    if (RST)
        Q <= 0;
    else if (SHIFT_EN)
        Q <= {1'b0, Q[3:1]};
end

endmodule
